"""
MKT Original Commentary — Proverbs chapters 25–27
Run: python3 scripts/zc-original-proverbs-25-27.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/glossary-hebrew.json
- data/translation/notes/proverbs.json
- data/translation/draft/mediating/proverbs.json

Key decisions in this range:
- Prov 26:4-5: the famous contradiction (do not answer / answer a fool) — these are
  not errors but dialectical wisdom; the MKT preserves the back-to-back placement as
  intentional, reflecting the wisdom tradition's embrace of situational judgment
- Prov 26:23: MKT 'silver glaze' — the MT has keseph sigim (silver dross/glaze)
  covering earthenware; Syriac had a different reading; MT preserved
- Prov 27:14: 'counted a curse' — qalalah (curse) applied to inappropriate praise,
  the idea that excessive or ill-timed blessing functions as a social insult
- Prov 25:1: the Hezekiah collection — this verse is a historically significant
  editorial note; the 'men of Hezekiah' are probably the scribal school attached to
  the palace that collected and edited earlier Solomonic proverbs
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "25": {
    "1": "<p><strong>gam-'elleh mishle shelomoh</strong> — &ldquo;these also are proverbs of Solomon.&rdquo; The editorial superscription signals a distinct collection. <em>He'etiqo</em> (H6275, to transfer, to copy, to preserve) is the verb for the scribal activity of the &ldquo;men of Hezekiah&rdquo; (<em>'anshei yechizqiyahu</em>). The historicity of the Hezekiah editorial connection (c. 715&ndash;686 BCE) is accepted by most commentators; the scribal school attached to the palace preserved older Solomonic material. This verse is one of the most precise editorial attributions in the wisdom literature.</p>",
    "2": "<p><strong>kevod 'elohim haster dabar</strong> — &ldquo;the glory of God to conceal a matter.&rdquo; <em>Kavod</em> (H3519, glory/weight) is used for the honor expressed through characteristic action; YHWH&rsquo;s glory is expressed in concealment (<em>haster</em>, the infinitive of <em>satar</em>, H5641, to hide/conceal). The royal counterpart is investigation: <em>ukhevod melakhim chaqor dabar</em> — &ldquo;and the glory of kings to search out a matter.&rdquo; <em>Chaqar</em> (H2713, to search out, investigate, explore) is the verb for thorough examination. The aphorism encodes a theology of the divine-human epistemic asymmetry: YHWH&rsquo;s mastery is displayed in what he keeps hidden; human mastery is displayed in what they can discover.</p>",
    "3": "<p><strong>shamayim laroom ve-'aretz le'amoq</strong> — &ldquo;the heavens for height, and the earth for depth.&rdquo; The inaccessible extremes of vertical space (sky/depth) frame the inaccessible interior of the king&rsquo;s heart: <em>ve-lev melakhim ein cheqer</em> — &ldquo;and the heart of kings is unsearchable.&rdquo; <em>Ein cheqer</em> (no searching/investigation possible) makes the royal heart as epistemically inaccessible as the cosmic extremes. The political wisdom of the aphorism: kings are not transparent, and their decisions come from depths that subjects cannot plumb.</p>",
    "4": "<p><strong>hago sigim mikkasef</strong> — &ldquo;remove dross from silver.&rdquo; <em>Sigim</em> (H5509, dross, the slag separated from metal in smelting) is the impurity that, once removed, allows the silversmith to produce a vessel (<em>keli</em>). The metallurgical metaphor for moral purification is applied in v5 to the political realm: remove the wicked from before the king, and the throne is established on righteousness. The technical vocabulary of metalworking applied to governance is characteristically Solomonic.</p>",
    "5": "<p><strong>hageh rasha' lifnei-melekh</strong> — &ldquo;remove the wicked from before the king.&rdquo; <em>Hagah</em> (H1898, here = to remove — related to the verb used of separating dross from silver in v4) makes explicit the parallel: wicked counselors are the dross of the royal court. <em>Ve-yikkon be-tzedeq kis'o</em> — &ldquo;and his throne will be established on righteousness.&rdquo; <em>Kun</em> in Niphal (to be established, to be secure, H3559) with <em>tzedeq</em> (righteousness, H6664) frames the stability of political rule as a moral outcome.</p>",
    "6": "<p><strong>'al-tit'addar lifnei-melekh</strong> — &ldquo;do not exalt yourself before the king.&rdquo; <em>Pa'ar</em> (H6286, to exalt oneself, to beautify/glorify oneself) in the Hithpael = self-glorification in the royal presence. <em>Uvimqom gedolim al-ta'amod</em> — &ldquo;and do not stand in the place of great men.&rdquo; The court wisdom of vv6-7 governs the behavior of those who seek royal favor: the voluntary assumption of a lower position is safer and ultimately more advantageous than the presumption of a higher one.</p>",
    "7": "<p><strong>ki tov 'emor-lecha 'aleh hennah</strong> — &ldquo;for it is better to be told, &lsquo;come up here,&rsquo; than to be put lower.&rdquo; The social mechanics of the royal court: <em>amur-lecha</em> (passive, &ldquo;it is said to you&rdquo;) is the invitation from above, more valuable than self-positioning. <em>Lifnei nodiv 'asher ra'u 'einecha</em> — &ldquo;in the presence of a noble whom your eyes have seen.&rdquo; The eyewitness qualifier grounds the aphorism in actual social experience rather than abstract principle.</p>",
    "8": "<p><strong>'al-tetze' la-riv mahir</strong> — &ldquo;do not go out hastily to court.&rdquo; <em>Mahir</em> (H4116, hastily, quickly) qualifies the danger: the problem is not litigation as such but premature litigation. <em>Pen mah-ta'aseh be'acharitah</em> — &ldquo;lest you know not what to do in the end when your neighbor has put you to shame.&rdquo; The shame scenario of v8 motivates the counsel of vv9-10: settle disputes privately rather than through public court, where humiliation is more likely.</p>",
    "9": "<p><strong>rivekhah riv 'et-re'akha</strong> — &ldquo;argue your case with your neighbor yourself.&rdquo; The instruction to keep disputes between the parties rather than escalating to public court. <em>Vesod 'acher 'al-tegal</em> — &ldquo;and do not reveal the secret of another.&rdquo; <em>Sod</em> (H5475, secret, confidential counsel) is the information shared in private counsel; to broadcast it in a legal dispute is to compound the wrong. The wisdom tradition consistently values the repair of relationship over the vindication of rights.</p>",
    "10": "<p><strong>pen yechasedkha shomea'</strong> — &ldquo;lest he who hears it bring shame on you.&rdquo; The social consequence of revealing secrets in litigation: <em>dibbatekha lo' tashuv</em> — &ldquo;your evil reputation will not turn back.&rdquo; <em>Dibbah</em> (H1681, defamation, evil report) once circulated cannot be retracted; the irreversibility of reputational damage is the warning. The wisdom tradition has a sober realism about the permanence of social facts.</p>",
    "11": "<p><strong>tapuchim zahav be-maskiyot kasef</strong> — &ldquo;golden apples in a silver setting.&rdquo; <em>Tapuach</em> (H8598, apple — or possibly quince or apricot; the golden-colored fruit) in a <em>maskiyot</em> (H4906, carved/latticed setting, a filigree or embossed work) of silver is the image of the precisely crafted decorative object. The beauty of the combination — gold fruit in silver setting — is the standard of excellence against which the <em>dabar dabar 'al-'ofanav</em> (word spoken on its occasions/wheels — i.e., at the right turning-point) is measured. The phrase &ldquo;spoken on its wheels&rdquo; suggests a word that arrives at the perfectly timed moment.</p>",
    "12": "<p><strong>nezem zahav ve-chaliy-paz</strong> — &ldquo;a gold ring and a fine-gold ornament.&rdquo; <em>Nezem</em> (H5141, ring — typically a nose-ring or ear-ring) of gold and a <em>chali paz</em> (H2481, ornament of <em>paz</em>, the finest refined gold) are luxury jewelry items. These represent a wise rebuker (<em>mochiach chakham</em>) to a listening ear (<em>'ozen shoma'at</em>): the skillful rebuke that is received is as valuable as the finest jewelry and, like a ring, stays with the person who receives it.</p>",
    "13": "<p><strong>ke-tzinnat-sheleg be-yom qatzir</strong> — &ldquo;like the coolness of snow in harvest time.&rdquo; <em>Tzinnah</em> (H6793, cold, the cold feeling) of <em>sheleg</em> (snow, H7950) during the harvest (<em>qatzir</em>, the hot dry season when snow itself is absent but cold water from snow-melt was stored) is the most refreshing experience imaginable in that climate. Applied to the <em>tzir ne'eman</em> (faithful messenger, H6735) — he refreshes (<em>meshiv</em>) the soul (<em>nefesh</em>) of his senders. The <em>nefesh</em> (H5315, the whole person/throat/life-force) refreshed by a reliable messenger captures the anxiety that surrounds delegated tasks.</p>",
    "14": "<p><strong>'anashim ruchot ve-geshem 'ain</strong> — &ldquo;clouds and wind but no rain.&rdquo; The meteorological frustration of the drought cloud (promising rain that never comes) is applied to <em>ish mit'hallel bemattan shaqer</em> — &ldquo;a man who boasts of a gift that does not exist.&rdquo; <em>Mit'hallel</em> (H1984 Hithpael, to boast, to brag) of a non-existent gift (<em>mattan shaqer</em>, false gift) matches anticipation to disappointment. The social failure of the promise-breaker has the same structure as the agricultural frustration of the dry cloud.</p>",
    "15": "<p><strong>be-'orekh ru'ach yefutteh qatzin</strong> — &ldquo;by long patience a ruler is persuaded.&rdquo; <em>'Orekh ru'ach</em> (long spirit, patient endurance) as a persuasive strategy for dealing with those in power. <em>Lashon rakkah tishbor-garem</em> — &ldquo;and a soft tongue breaks a bone.&rdquo; The paradox: the physically yielding tongue (<em>rakkah</em>, H7390, soft, gentle) is more effective at breaking the hard (<em>garem</em>, bone, H1634 — the hardest material of the body) than force. The inversion of expected physical causation is the wisdom insight about the power of patient, gentle speech.</p>",
    "16": "<p><strong>devash matzata 'echol daieka</strong> — &ldquo;if you find honey, eat only what you need.&rdquo; <em>Dai</em> (H1767, sufficiency, enough) qualifies the honey-consumption: wisdom in eating is knowing when to stop. <em>Pen-tis'benu vahaqe'ota</em> — &ldquo;lest you be full and vomit it up.&rdquo; The physical outcome of over-indulgence (<em>qe'</em>, vomiting) provides the vivid warning against the pleasures that become repulsive when taken to excess. The honey metaphor applies broadly to any good thing that becomes harmful through excess.</p>",
    "17": "<p><strong>hoker ragelcha mibeit re'echa</strong> — &ldquo;let your foot be seldom in your neighbor&rsquo;s house.&rdquo; <em>Yaqar</em> (H3365, rare, precious — the Hiphil here = to make rare/scarce) applied to one&rsquo;s presence at a neighbor&rsquo;s house is the idiom for maintaining appropriate social distance. <em>Pen-yisba'akha ushne'akha</em> — &ldquo;lest he be full of you and hate you.&rdquo; The social observation: familiarity that exceeds the natural limit produces saturation (<em>sava'</em>, H7646) and then aversion (<em>sana'</em>, hatred). Wisdom about social relationships includes knowing when one&rsquo;s presence is welcome and when it has become an imposition.</p>",
    "18": "<p><strong>mefitz ve-cherev ve-chetz shannun</strong> — &ldquo;a club, a sword, and a sharp arrow.&rdquo; The three weapons of war are the simile for <em>'ish 'oneh bere'ehu 'ed shaqer</em> — &ldquo;a man who bears false witness against his neighbor.&rdquo; The false witness in the legal system functions as a weapon of assault: the language is not metaphorical exaggeration but a precise moral equivalence. Judicial perjury is assault and attempted murder, not merely dishonesty.</p>",
    "19": "<p><strong>shen ro'ah ve-regel mu'adeth</strong> — &ldquo;a broken tooth and a faltering foot.&rdquo; Two sources of pain and mechanical failure (the tooth that cannot chew, the foot that cannot bear weight) are the image of <em>mivtach boged be-yom tzarah</em> — &ldquo;confidence in an unfaithful man in a time of trouble.&rdquo; <em>Boged</em> (H898, treacherous/faithless person) at precisely the moment of crisis (<em>yom tzarah</em>): the failure comes exactly when the support was needed most. The physical similes capture both the pain of the failure and its practical uselessness.</p>",
    "20": "<p><strong>mafshit beged be-yom qarah</strong> — &ldquo;one who removes a garment on a cold day.&rdquo; The social obtuseness of the wrong response to a context: stripping clothing in the cold is not merely useless but actively harmful. Applied in parallel to <em>shir shir 'al-lev ra'</em> — &ldquo;singing songs to a heavy heart.&rdquo; <em>Lev ra'</em> (heavy/evil heart, a heart in distress) confronted with cheerful singing suffers a double insult: the tone of the response is the opposite of what the situation requires. The wisdom of social responsiveness includes reading the emotional temperature of others.</p>",
    "21": "<p><strong>im ra'ev sone'akha ha'achilenu lechem</strong> — &ldquo;if your enemy is hungry, give him bread to eat.&rdquo; <em>Sone'akha</em> (the one who hates you, your enemy, H8130) as the specific recipient of charity extends the social ethic beyond those one likes. The specificity of the command — <em>ha'achilenu lechem</em> (give him bread to eat) and <em>hashqehu mayim</em> (give him water to drink) — grounds the abstract enemy-love in concrete material provision. The NT quotation in Rom 12:20 keeps these specific material forms.</p>",
    "22": "<p><strong>ki gechalim 'atah chotheh 'al-ro'sho</strong> — &ldquo;for you will heap burning coals on his head.&rdquo; <em>Gechalim</em> (H1513, glowing coals, burning embers) heaped on the head is the most contested phrase in the chapter. Interpretations include: (a) the coals of shame — the enemy&rsquo;s shame at receiving unexpected kindness; (b) the coals of refining fire — the act of kindness that burns away enmity and produces change; (c) an Egyptian ritual of public penitence where a basin of coals was carried on the head as a sign of contrition. The MKT preserves the ambiguity. <em>Ve-YHWH yeshallem-lakh</em> — &ldquo;and the LORD will reward you&rdquo;: the theological grounding of the ethic.</p>",
    "23": "<p><strong>ru'ach tzafon techollel geshem</strong> — &ldquo;the north wind brings rain.&rdquo; In Palestine, the north wind typically brings dry weather; some commentators suggest the text may reflect a different climatic observation or a reference to northwest winds. <em>Ufanim nilozah lashon sater</em> — &ldquo;and a slanderous tongue brings angry faces.&rdquo; The structure is cause-and-effect: the <em>lashon sater</em> (tongue of secrecy, the one who gossips in private) inevitably produces <em>panim nilozah</em> (angry countenance). The meteorological certainty of the wind-rain connection is applied to the social certainty of the slander-anger connection.</p>",
    "24": "<p><strong>tov shevet 'al-pinnot gag</strong> — &ldquo;better to live in a corner of the roof.&rdquo; The corner of the flat-roofed Palestinian house (exposed to the elements, cramped) is preferred to <em>mimishqal beith chaver</em> — &ldquo;a house shared with a quarrelsome wife.&rdquo; <em>Midyan</em> (H4066, contention/strife — used also in Prov 21:9) is the word for the contentious personality. The repetition of this aphorism (cf. 21:9) reflects its status as an established unit in the oral wisdom tradition. The hyperbole (rooftop > full house) encodes the wisdom that relational peace exceeds material comfort.</p>",
    "25": "<p><strong>mayim qarim 'al-nefesh 'ayefah</strong> — &ldquo;cold water to a weary soul.&rdquo; <em>Nefesh 'ayefah</em> (H5315 + H5889, a weary/exhausted nephesh) uses the whole-person vocabulary of Hebrew anthropology: the <em>nefesh</em> is not merely the inner spirit but the entire embodied person whose throat is parched with thirst. <em>Shmu'ah tovah me'eretz marchaq</em> — &ldquo;good news from a distant land&rdquo;: the comparison equates the physical relief of cold water with the emotional and social relief of positive tidings from far away. The word <em>shmu'ah</em> (H8052, report, news, rumor) is the term used in Isa 53:1 (&ldquo;who has believed our report?&rdquo;).</p>",
    "26": "<p><strong>ma'ayan nidrakh umaqor mashhath</strong> — &ldquo;a muddied spring and a polluted fountain.&rdquo; <em>Nidrakh</em> (H7512 in MT, some manuscripts have <em>nirpas</em> = trampled) describes a water source rendered unusable by disturbance. The image applies to <em>tzaddiq mat lifnei rasha'</em> — &ldquo;a righteous man who gives way before the wicked.&rdquo; The corruption of a water source destroys its usefulness; the collapse of the righteous before wickedness destroys the community&rsquo;s moral resource. The righteous person&rsquo;s role in the community is compared to a spring: essential, potentially ruinable.</p>",
    "27": "<p><strong>'akhol devash harbeh lo'-tov</strong> — &ldquo;it is not good to eat too much honey.&rdquo; The honey-excess warning of v16 returns as a frame for the final aphorism: <em>ve-cheqer khevod-khavod</em> — &ldquo;and to seek one&rsquo;s own glory is not glory.&rdquo; The second clause is syntactically terse; the most natural reading parallels the honey: just as too much honey is bad, so too much self-promotion collapses the glory it seeks. <em>Kavod</em> pursued directly dissolves; <em>kavod</em> that comes from others or from achievement is the only genuine article.</p>",
    "28": "<p><strong>'ein ma'atsar le-rucho</strong> — &ldquo;a man who has no control over his spirit.&rdquo; <em>Ma'atsar</em> (H4623, restraint, control) is the capacity to contain and direct the <em>ru'ach</em> (H7307, spirit, breath, disposition). The city without walls (<em>'ir paruzah 'ein chomah</em>) is the political image for the person without self-containment: militarily indefensible, permanently vulnerable, exposed to every attack. The architectural-political metaphor is applied to the inner life of the person who has not cultivated the capacity for self-restraint.</p>"
  },
  "26": {
    "1": "<p><strong>kashseleg baqqayitz</strong> — &ldquo;like snow in summer.&rdquo; The two meteorological impossibilities — snow at harvest, rain at planting-time (more precisely: <em>qatzir</em> is the dry harvest season) — frame the social impossibility of <em>kavod le-khesil</em> (honor for a fool). <em>Kesil</em> (H3684, the self-confident fool who is morally insensitive rather than merely ignorant) receiving honor is as incongruous and destructive as unseasonal weather ruining the crops. The comparison encodes the claim that social recognition systems have a moral ecology that is disrupted by misplaced honor.</p>",
    "2": "<p><strong>ke-tzippor la-nud kadsror la-'uf</strong> — &ldquo;like a sparrow in its flitting, like a swallow in its flying.&rdquo; The birds in aimless motion go nowhere in particular; applied to <em>qillelat chinnam lo' tavo'</em> — &ldquo;a causeless curse does not land.&rdquo; <em>Chinnam</em> (H2600, without cause/ground, for nothing) qualifies the curse: a curse without genuine ground to land on cannot alight, just as a swallow not aimed at anything particular just circles. The aphorism reflects the wisdom tradition&rsquo;s belief that curses are not mere speech-acts but instruments that require a moral landing-spot to be effective.</p>",
    "3": "<p><strong>shot la-sus umetheg la-chamor</strong> — &ldquo;a whip for the horse, a bridle for the donkey.&rdquo; The tools of animal control (<em>shot</em>, whip; <em>mtheg</em>, bridle) are paired with the appropriate instrument for human correction: <em>shevet le-gev kesilim</em> — &ldquo;a rod for the back of fools.&rdquo; The rod (<em>shevet</em>, also a tribal scepter and a shepherd&rsquo;s staff) applied to the fool&rsquo;s back is the appropriate instrument for those who have not responded to verbal instruction. The tool-to-subject matching implies that each category of being has its appropriate corrective instrument.</p>",
    "4": "<p><strong>'al-ta'an kesil ke'evvalto</strong> — &ldquo;do not answer a fool according to his folly.&rdquo; The first of the famous pair (vv4-5) advises silence: responding on the fool&rsquo;s own terms (<em>ke'evvalto</em> — according to his folly/in his folly&rsquo;s mode) transforms the responder into the same kind of person (<em>tishveh-lo gam-'attah</em> — &ldquo;lest you also become like him&rdquo;). The warning is about the contaminating effect of engaging on the fool&rsquo;s terms.</p>",
    "5": "<p><strong>'aneh kesil ke'evvalto</strong> — &ldquo;answer a fool according to his folly.&rdquo; The immediately following counter-instruction advises response: if you do not answer (<em>pen-yihyeh chakham be'einav</em> — &ldquo;lest he be wise in his own eyes&rdquo;), the fool&rsquo;s false self-assessment goes unchallenged. The two verses together (<em>vv4-5</em>) encode the wisdom of situational judgment: sometimes responding on the fool&rsquo;s terms ensnares you; sometimes not responding lets him become entrenched in his foolishness. The wisdom tradition preserves both proverbs deliberately, leaving the decision about which situation applies to the practitioner.</p>",
    "6": "<p><strong>qotze' raglayim</strong> — &ldquo;cutting off one&rsquo;s own feet.&rdquo; The graphic image of self-amputation (<em>qataz</em>, H7112, to cut off; <em>raglayim</em>, feet/legs) applied to the one who sends a message by a fool (<em>sholeach devarim be-yad kesil</em>). The secondary result is <em>shote chamas</em> — &ldquo;drinking violence&rdquo; — experiencing the violence that comes back from the foolish messenger&rsquo;s bungling. The delegator who uses an unfit agent bears the consequences of the agent&rsquo;s incompetence.</p>",
    "7": "<p><strong>dallyu shaqayim me-pisseach</strong> — &ldquo;the legs of the lame hang limp.&rdquo; The <em>shaqayim</em> (H7785, thighs/legs) of the <em>pisseach</em> (lame person, H6455) that dangle uselessly are compared to <em>mashal be-fi kesilim</em> — &ldquo;a proverb in the mouth of fools.&rdquo; The proverb is a tool for the wise; in the mouth of the fool it is as useless as a lame man&rsquo;s legs: structurally present but functionally inoperative. The wisdom tradition&rsquo;s self-awareness: its instruments require the right user to work.</p>",
    "8": "<p><strong>ki-tzror 'even bimargema</strong> — &ldquo;like tying a stone to a sling.&rdquo; The <em>margema</em> (H4773, sling-stone heap/sling) with a stone permanently attached (<em>tzror</em>, bound up in) cannot function: the stone can no longer be aimed and released. Applied to <em>ken noten le-khesil kavod</em> — &ldquo;so is giving honor to a fool&rdquo;: honor attached to a fool is as counterproductive as a stone tied to its sling. It defeats the purpose of the honor-system rather than serving it.</p>",
    "9": "<p><strong>choach 'alah be-yad shikkor</strong> — &ldquo;a thorn-branch in the hand of a drunkard.&rdquo; The <em>choach</em> (H2336, thorn, brier, specifically a thorny branch) in the hand of a <em>shikkor</em> (H7910, drunk person) is dangerous precisely because the drunkard has no control over where the thorns point. Parallel to <em>mashal be-fi kesilim</em> — a proverb in the mouth of fools: as the drunk brandishes the thorn without direction, the fool brandishes the proverb without discernment, injuring indiscriminately.</p>",
    "10": "<p><strong>rav mecholel-kol</strong> — &ldquo;a great archer/employer who wounds all.&rdquo; The verse is one of the most textually difficult in Proverbs; the MT is uncertain. The MKT follows the reading of a shooter or master-worker (<em>rav</em>, H7227) whose indiscriminate hiring of the fool and the passerby (<em>ve-socher kesil ve-socher 'overim</em>) produces random harm. The managerial wisdom: hiring without discrimination is not generosity but irresponsibility that harms the organization and the employees.</p>",
    "11": "<p><strong>ke-kelev shav 'al-qe'o</strong> — &ldquo;like a dog that returns to its vomit.&rdquo; <em>Kelev</em> (dog, H3611) returning to <em>qe'o</em> (its vomit, H6892) is one of the most vivid images in Proverbs for the fool who repeats his folly. <em>Sakhel shoneh be-'ivvalto</em> — &ldquo;so is a fool who repeats his foolishness.&rdquo; The biological compulsion of the animal&rsquo;s return to vomit is applied to the psychological pattern of the fool who cannot learn from experience. 2 Pet 2:22 quotes this verse exactly, applying it to those who return to a life of sin after knowledge of the truth.</p>",
    "12": "<p><strong>ra'ita 'ish chakham be'einav</strong> — &ldquo;do you see a man wise in his own eyes?&rdquo; The rhetorical question presents the <em>chakham be'einav</em> (wise in his own eyes — the self-assessor who has privileged his own judgment over external reality-testing) as someone in a worse condition than the outright fool. <em>Tiqvah le-khesil mimmenu</em> — &ldquo;there is more hope for a fool than for him.&rdquo; The fool knows he is not wise and might be teachable; the self-wise person has closed the feedback loop. This is the wisdom tradition&rsquo;s most severe critique.</p>",
    "13": "<p><strong>'amar 'atzel shachal badarekh</strong> — &ldquo;the sluggard says: there is a lion in the road.&rdquo; <em>'Atzel</em> (H6102, sluggard, lazy person) is the character type who constructs elaborate reasons for inaction. The lion-in-the-road (<em>shachal</em>, H7826, a specific lion term) and the <em>'ari bein harechavot</em> (lion among the streets) are escalating fantasies of danger. The wisdom tradition&rsquo;s psychological observation: laziness generates its own rationalizations, and the rationalizations become increasingly implausible as the pattern solidifies.</p>",
    "14": "<p><strong>delet tisov 'al-tziyrah</strong> — &ldquo;a door turns on its hinges.&rdquo; The <em>tziyrah</em> (H6735, hinge/pivot) as the pivot-point around which the door moves without going anywhere is the image of the <em>'atzel 'al-mittatho</em> — &ldquo;the sluggard on his bed.&rdquo; The door swings repeatedly on its hinge: the sluggard turns repeatedly on his bed. Maximum motion, zero progress. The mechanical precision of the image (the door&rsquo;s kinetic activity that produces no displacement) captures the sluggard&rsquo;s energetic non-productivity.</p>",
    "15": "<p><strong>taman 'atzel yado batzalachat</strong> — &ldquo;the sluggard buries his hand in the dish.&rdquo; The hand in the bowl (<em>tzalachat</em>, H6745, a dish/bowl) unable to complete the circuit back to the mouth (<em>nil'ah lehashivah el-pihu</em> — &ldquo;it wearies him to bring it back to his mouth&rdquo;) is the comic absurdity of laziness taken to its logical extreme. The sluggard has enough motivation to begin eating but not to complete the action. The comedic exaggeration makes the point through humor: laziness, pushed to its extreme, becomes self-destructive in the most basic biological activity.</p>",
    "16": "<p><strong>chakham 'atzel be'einav</strong> — &ldquo;the sluggard is wiser in his own eyes.&rdquo; The sluggard&rsquo;s self-assessment (<em>chakham be'einav</em> — wise in his own eyes) places him in the category of 26:12: the most dangerous fool is the self-assessed wise person. Applied to <em>shiv'ah meshivim ta'am</em> — &ldquo;seven men who answer with reason/taste.&rdquo; The sluggard considers himself wiser than seven thoughtful people; seven being the number of completeness, his self-wisdom exceeds every possible counsel.</p>",
    "17": "<p><strong>machaziq be'oznei-khalev 'over</strong> — &ldquo;grabbing the ears of a passing dog.&rdquo; The image of the <em>mit'abber</em> (H5674 Hithpael, one who passes by, who involves himself) in a quarrel not his own (<em>rib lo' lo</em> — &ldquo;a quarrel not belonging to him&rdquo;) is captured by the dog-ear-grabber: the action draws immediate and disproportionate retaliation. Grabbing a dog&rsquo;s ears transforms a non-threat into an immediate threat. The wisdom observation about the danger of uninvited intervention in others&rsquo; conflicts.</p>",
    "18": "<p><strong>ke-mitolelah hayoreh ziqim</strong> — &ldquo;like a madman shooting firebrands.&rdquo; <em>Mitolel</em> (H3856, a madman, one who acts as if deranged) who shoots <em>ziqim</em> (H2131, fire-arrows, firebrands — incendiary missiles) and arrows and death-dealing objects at random: the image is of indiscriminate dangerous behavior by someone with no accountability structure. Applied in v19 to the deceiver who &ldquo;plays&rdquo; and then claims it was all a joke.</p>",
    "19": "<p><strong>kakhah ha'ish rimmah 'et-re'ehu</strong> — &ldquo;so is the man who deceives his neighbor.&rdquo; The deceiver who says <em>halo'-mesacheq 'ani</em> — &ldquo;wasn't I just playing?&rdquo; — after the harm is done is as dangerous as the firebrand-shooter: the playfulness-claim does not undo the damage. <em>Ramah</em> (H7411, to deceive, to throw down, to beguile) combined with the joke-defense (<em>mesacheq</em>, H7832) represents the use of humor as a shield for malicious action — a form of social weaponization that the wisdom tradition explicitly names and condemns.</p>",
    "20": "<p><strong>be-'efes 'etzim tikbeh-'esh</strong> — &ldquo;without wood, a fire goes out.&rdquo; The elimination of the fuel source as the mechanism of fire-extinction is applied directly to social conflict: <em>uv'ein nirgan yishtoq madon</em> — &ldquo;and without a gossip/whisperer, strife dies down.&rdquo; <em>Nirgan</em> (H5372, a whisperer, a murmurer who spreads slanderous reports) is the social fuel of conflict; remove the gossip, and the quarrel has no energy source. The passive <em>yishtoq</em> (becomes quiet, ceases) implies the natural resolution of conflict that has been deprived of its supply line.</p>",
    "21": "<p><strong>pechami le-gechalim ve-'etzim le-'esh</strong> — &ldquo;charcoal to embers and wood to fire.&rdquo; The first parallel of fuel-to-fire adds the specific fuel types: <em>pecham</em> (H6352, charcoal) to <em>gechalim</em> (H1513, glowing embers — cf. Prov 25:22) and wood (<em>'etzim</em>) to fire (<em>'esh</em>). The social parallel is <em>ve-'ish midyanim le-charet madon</em> — &ldquo;and a contentious man for kindling strife.&rdquo; <em>Midyan</em> (H4066, contention, strife-causing behavior) and <em>charet</em> (H2750, burning, heating-up) complete the fire-metaphor: the contentious person is the fuel that ignites and sustains social conflict.</p>",
    "22": "<p><strong>divrei nirgan ke-mitlahamim</strong> — &ldquo;the words of a gossip are like delicious morsels.&rdquo; <em>Mitlahamim</em> (H3859, something eagerly swallowed down, delicious morsels — related to the verb meaning to gulp down with pleasure) captures the appealing quality of gossip: it is consumed with relish. <em>Ve-hem yardu chadrei-vaten</em> — &ldquo;they go down into the inner chambers of the belly.&rdquo; <em>Chadrei vaten</em> (the innermost chambers of the body) implies deep, lasting penetration: what enters as gossip settles into the deepest recesses of memory and shapes perception in ways that are difficult to dislodge. Gossip is not only appealing but persistent.</p>",
    "23": "<p><strong>kesef sigim mezhupach 'al-chares</strong> — &ldquo;silver glaze spread over earthenware.&rdquo; <em>Sigim</em> (dross/glaze, H5509) — the residue of silver-smelting — spread (<em>mezhupach</em>, H2645, covered with) over <em>chares</em> (earthenware/pottery, H2789) creates the appearance of silver on an object that is actually clay. The appearance of quality covers base material: applied to <em>sefatayim dolqim ve-lev ra'</em> — &ldquo;fervent/burning lips with an evil heart.&rdquo; The false surface conceals a contrary interior, which is the definition of the hypocrite in the wisdom tradition.</p>",
    "24": "<p><strong>be-sefatav yinnaker sone'</strong> — &ldquo;an enemy disguises himself with his lips.&rdquo; <em>Nakar</em> (H5234 Niphal, to be recognized — here in the sense of disguising oneself to be unrecognizable) through <em>sefatayim</em> (lips) captures the use of speech as a costume for concealing hatred. <em>Uve-qirbo yasit mirmah</em> — &ldquo;but he harbors deceit within himself.&rdquo; <em>Mirmah</em> (H4820, deceit, treachery — the cunning action word for intentional deception) stored in the interior while pleasant words flow externally: the psychology of the hidden enemy.</p>",
    "25": "<p><strong>ki-yachnen qolo 'al-ta'amen bo</strong> — &ldquo;when his voice becomes gracious, do not trust him.&rdquo; <em>Chanan</em> (H2603, to be gracious, to show favor — the root of the name Hannah) applied to an enemy&rsquo;s voice is the warning sign: exceptional graciousness from someone with a history of enmity is a manipulation signal. <em>Ki sheva' to'avot be-libbo</em> — &ldquo;for seven abominations are in his heart.&rdquo; Seven = completeness; the full quota of the detestable is stored behind the pleasant voice.</p>",
    "26": "<p><strong>tikkaseh sin'ah be-mirmah</strong> — &ldquo;though hatred covers itself with deceit.&rdquo; The sequence vv24-26 traces the arc of the hidden enemy: disguise (v24), stored deceit (v24b), gracious voice (v25), and now the moment when the disguise fails: <em>tigaleh ra'ato biqhal</em> — &ldquo;his wickedness will be exposed in the assembly.&rdquo; <em>Qahal</em> (H6951, assembly, the gathered community) is the social context in which private concealment becomes public revelation. The wisdom tradition&rsquo;s confidence that concealed wickedness will be exposed has the assembly as the medium of disclosure.</p>",
    "27": "<p><strong>koreh-shachat bah yippol</strong> — &ldquo;whoever digs a pit will fall into it.&rdquo; The pitfall (<em>shachat</em>, H7845, pit/trap dug for prey) turns against its digger: the mechanism of the trap reverses. <em>Ve-golel 'even 'elav tashuv</em> — &ldquo;and whoever rolls a stone will have it roll back on them.&rdquo; The stone-rolling returns to the source by the same gravitational logic. Both images express the principle of the self-defeating trap: malicious action directed against others rebounds on the actor. The Galatians 6:7-8 principle (&ldquo;whatever one sows, that will he also reap&rdquo;) is the NT formulation of the same moral physics.</p>",
    "28": "<p><strong>lashon sheqer yisna' dakkav</strong> — &ldquo;a lying tongue hates those it crushes.&rdquo; <em>Dakka'</em> (H1793, crushed/oppressed) as the victim of the lying tongue reveals the hatred beneath the speech act: the lie is not merely a strategic tool but an expression of genuine hatred for the person being destroyed. <em>Ufeh chalaq ya'aseh midcheh</em> — &ldquo;and a flattering mouth causes ruin.&rdquo; <em>Midcheh</em> (H4072, overthrow, ruin) as the outcome of <em>peh chalaq</em> (the smooth/flattering mouth): the pleasant speech that is oriented toward destruction is itself an act of hatred.</p>"
  },
  "27": {
    "1": "<p><strong>'al-tit'hallel be-yom machar</strong> — &ldquo;do not boast about tomorrow.&rdquo; <em>Hithpael</em> of <em>hallel</em> (H1984, to praise/boast — the same root as <em>hallelujah</em>) applied to the future (<em>yom machar</em>, the day of tomorrow) as the act of claiming tomorrow&rsquo;s outcomes as if they were already secured. <em>Ki lo' teda' mah-yeled yom</em> — &ldquo;for you do not know what a day may bring forth.&rdquo; <em>Yalad</em> (H3205, to bear/give birth) applied to the day: the day gives birth to its events, and those events are not known in advance. The birth-metaphor emphasizes the unpredictability of what tomorrow will produce.</p>",
    "2": "<p><strong>yehallalcha zar ve-lo' picha</strong> — &ldquo;let another praise you, and not your own mouth.&rdquo; <em>Zar</em> (H2114, a stranger, an outsider, one outside the family or community) as the preferred source of praise inverts ordinary expectations: genuine praise comes from those with no stake in flattering you. <em>Nokri ve-lo' sefatecha</em> — &ldquo;a foreigner, and not your own lips&rdquo;: the emphasis on the source (&ldquo;outside&rdquo;, &ldquo;foreign&rdquo;) implies that self-praise is self-serving and therefore unreliable. Third-party evaluation is epistemically more trustworthy than self-assessment.</p>",
    "3": "<p><strong>kovedh'even venatle'h hakholem</strong> — &ldquo;a stone is heavy and sand is weighty.&rdquo; The two standard weights (stone and sand) that are heavy in the physical realm frame the comparison: <em>veka'as 'evil kaved mishnihem</em> — &ldquo;but a fool&rsquo;s provocation is heavier than both.&rdquo; <em>Ka'as</em> (H3708, vexation, provocation, irritation) and <em>'evil</em> (H191, the fool — specifically the morally arrogant fool) combine to produce a social weight more burdensome than physical loads. The aphorism quantifies the cost of dealing with provocative foolishness.</p>",
    "4": "<p><strong>achzariyut chemah ve-sheetef 'af</strong> — &ldquo;wrath is cruel, and anger is overwhelming.&rdquo; <em>Achzariyut</em> (H394, cruelty, ruthlessness) qualifies <em>chemah</em> (H2534, wrath, hot fury — the burning aspect of anger); <em>shetteph</em> (H7858, flood, overwhelming torrent) qualifies <em>'af</em> (H639, nose/nostrils as the seat of anger, the physiological expression of anger through flared nostrils). Both forms of anger are destructive. But the superlative follows: <em>umi ya'amod lifnei qin'ah</em> — &ldquo;and who can stand before envy/jealousy?&rdquo; <em>Qin'ah</em> (H7068, jealousy/envy — the possessive intense desire that cannot tolerate rivals) exceeds even wrath and anger as the most powerful of the negative passions.</p>",
    "5": "<p><strong>tov tokhachat megullah me'ahavah mesuteret</strong> — &ldquo;better is open rebuke than hidden love.&rdquo; <em>Tokhachat</em> (H8433, rebuke, reproof) that is <em>megullah</em> (H1540, revealed, open, uncovered) exceeds love that is <em>mesuteret</em> (hidden, concealed, H5641). The paradox: hidden love that fails to correct when correction is needed is inferior to open rebuke that risks the relationship for the sake of the person&rsquo;s genuine good. The wisdom tradition consistently values the truthful act over the pleasant.</p>",
    "6": "<p><strong>ne'emanim pitz'ei 'ohev</strong> — &ldquo;the wounds of a friend are trustworthy.&rdquo; <em>Petzah</em> (H6481, wound, injury) that is <em>ne'emanim</em> (H539, trustworthy, faithful) paradoxically: the wounding action of genuine friendship is reliable precisely because it aims at the friend&rsquo;s good rather than the friendship&rsquo;s preservation. <em>Ve-na'tarot neshiqot sone'</em> — &ldquo;but an enemy&rsquo;s kisses are lavish and false.&rdquo; <em>Na'tar</em> (H6280, excessive, lavish, insincere) qualifies the enemy&rsquo;s kisses (<em>neshiqot</em>): they are abundant precisely because they are cheap — not costly as the friend&rsquo;s wound is costly.</p>",
    "7": "<p><strong>nefesh seva'ah toosah nofeth</strong> — &ldquo;a full soul tramples on honeycomb.&rdquo; <em>Nefesh seva'ah</em> (a satisfied/full <em>nefesh</em>) is the person whose appetite is already met; for such a person even <em>nofeth</em> (H5317, honeycomb drippings — the most desirable form of honey) is despised. <em>Ve-nefesh re'evah kol-mar matok</em> — &ldquo;but to a hungry <em>nefesh</em>, even what is bitter is sweet.&rdquo; The reversal: the hungry person finds bitterness sweet. The principle of appetite governing perception applies not only to food but to all human goods and especially to wisdom.</p>",
    "8": "<p><strong>ke-tzippor nodedeth min-qinah</strong> — &ldquo;like a bird that wanders from its nest.&rdquo; The <em>tzippor</em> (bird, H6833) that <em>nodedeth</em> (wanders, flees, H5074) from its <em>qen</em> (nest, H7064) is vulnerable, displaced from its place of safety and belonging. Applied to <em>ken 'ish noded mi-meqomo</em> — &ldquo;so is a man who wanders from his place.&rdquo; <em>Maqom</em> (H4725, place, one&rsquo;s established location in community) as the social nest: the person who wanders from his social-relational home is as exposed as the nestless bird.</p>",
    "9": "<p><strong>shemen viqetoret yessammach-lev</strong> — &ldquo;oil and perfume bring joy to the heart.&rdquo; <em>Shemen</em> (H8081, oil — used in festive anointing and in cooking) and <em>qetoret</em> (H7004, incense/perfume) as the physical means of joy and celebration. <em>Ve-methaq re'ehu me'atzat-nefesh</em> — &ldquo;and the sweetness of a friend comes from earnest counsel.&rdquo; <em>Me'atzat nefesh</em> (&ldquo;from counsel of the soul/self&rdquo; — genuine counsel that comes from the friend&rsquo;s whole inner engagement rather than from social performance) is the human analog of sensory pleasures: it makes the heart joyful in the way that fragrance makes the body joyful.</p>",
    "10": "<p><strong>re'akha ve-re'a 'avicha 'al-ta'azov</strong> — &ldquo;do not forsake your friend and your father&rsquo;s friend.&rdquo; The inherited friend (<em>re'a 'avicha</em>, your father&rsquo;s friend) is the intergenerational relational capital that connects a person to a community of support. <em>Uve-yom 'edkha 'al-tavo' beit 'achicha</em> — &ldquo;and do not go to your brother&rsquo;s house on the day of your trouble.&rdquo; The proximity-caveat: a distant friend who knows you may be more reliable than a nearby relative who does not. <em>Tov shakhein qarov me-'ach rachok</em> — &ldquo;better a neighbor who is near than a brother who is far away.&rdquo;</p>",
    "11": "<p><strong>chakham beni ve-ssammach libbi</strong> — &ldquo;be wise, my son, and bring joy to my heart.&rdquo; The parental investment in the son&rsquo;s wisdom returns to the paternal-address frame of chs 1-9. <em>Ve-'ashivah chorphi dabar</em> — &ldquo;so that I may answer him who reproaches me.&rdquo; The father&rsquo;s own honor in the community depends in part on the son&rsquo;s wisdom: the son&rsquo;s foolishness would be used as reproach against the father. The communal accountability structure of wisdom formation: the teacher&rsquo;s reputation is implicated in the student&rsquo;s life.</p>",
    "12": "<p><strong>'arum ra'ah ra'ah venisttah</strong> — &ldquo;the prudent man sees danger and hides himself.&rdquo; <em>'Arum</em> (H6175, prudent, shrewd — the same word used of the serpent in Gen 3:1) paired with <em>ra'ah</em> (saw, perceived the evil) and <em>nisttah</em> (H5641 Niphal, hid himself) is the positive use of the same foresight that protects the <em>'arum</em> from harm. <em>Upethaim 'avru ve-ne'nashtu</em> — &ldquo;the simple pass on and are punished.&rdquo; The simple (<em>pethaim</em>) who see the same danger but do not respond appropriately suffer the consequence. The difference between prudence and simpleness is not intelligence but responsiveness to danger-signals.</p>",
    "13": "<p><strong>qach bigdo ki-'arav zar</strong> — &ldquo;take his garment when he has guaranteed for a stranger.&rdquo; The collateral-seizure instruction (take the pledge-garment, the <em>beged</em>) when someone has co-signed for a foreigner (<em>zar</em>) repeats the warning of 20:16 and 6:1-5. The practical wisdom about credit risk: guaranteeing for strangers or foreigners carries a higher default risk than guaranteeing for members of one&rsquo;s own community where social accountability mechanisms apply.</p>",
    "14": "<p><strong>mevareikh re'ehu beqol gadol</strong> — &ldquo;whoever blesses his neighbor with a loud voice early in the morning.&rdquo; The excessive and poorly-timed blessing (<em>qol gadol</em>, loud voice; <em>baboqer hashkiem</em>, rising early in the morning when people are asleep or barely awake) is identified as a social violation: <em>qillelah techashev-lo</em> — &ldquo;it will be counted as a curse to him.&rdquo; <em>Qillelah</em> (H7045, a curse) as the result of poorly-calibrated enthusiasm: the intention does not determine the effect; the social context and timing do. Inappropriate expression of good will can be as harmful as its absence.</p>",
    "15": "<p><strong>delet nittefeth be-yom sag-rim</strong> — &ldquo;a continually dripping roof in a day of heavy rain.&rdquo; <em>Nittaf</em> (H5197, to drop, to drip) characterizes the <em>delet</em> (door/roof, H1817) in the context of steady rain (<em>sag-rim</em>, pouring rain): the leak that cannot be escaped, the persistent irritation that the rain makes worse. Applied to <em>ve-'eshet midyanim nishtavah</em> — &ldquo;and a quarrelsome wife are alike&rdquo;: the contentious woman and the leaking roof share the quality of persistent, inescapable irritation. The aphorism is about the structural inevitability of the annoyance, not a moral judgment on the person.</p>",
    "16": "<p><strong>tzofeneyha tzafan ru'ach</strong> — &ldquo;to restrain her is to restrain the wind.&rdquo; The contentious woman of v15 cannot be &ldquo;restrained&rdquo; (<em>tzafan</em>, H6845, to hide, to store up, to restrain) any more than wind can be stored. <em>Ve-shemen yemino yiqra'</em> — &ldquo;and oil in one&rsquo;s right hand encounters himself&rdquo; — a difficult clause; the most natural reading suggests that attempting to grasp oil (which flows through the fingers) is the analog of trying to manage the contentious person. The impossibility-metaphors frame the proverb as an observation, not a counsel of despair.</p>",
    "17": "<p><strong>barzel be-varzel yad</strong> — &ldquo;iron sharpens iron.&rdquo; The metallurgical process of sharpening (<em>chad</em>, H2300) requires the hard-on-hard contact of iron (<em>barzel</em>, H1270) striking iron. No softer material could accomplish the sharpening. <em>Ve-'ish yachad penei-re'ehu</em> — &ldquo;so one man sharpens the face of another.&rdquo; <em>Penei</em> (face, H6440) as the external presentation of the person — the confrontation of one person&rsquo;s face (perspective, challenge) with another&rsquo;s produces the sharpening that neither could achieve alone. The Hebrews 10:24 call to &ldquo;stir up one another&rdquo; stands in this tradition.</p>",
    "18": "<p><strong>notzer te'enah yo'khal piryah</strong> — &ldquo;whoever tends a fig tree will eat its fruit.&rdquo; <em>Natsar</em> (H5341, to watch over, guard, keep) applied to the <em>te'enah</em> (fig tree, H8384) captures the patient, sustained attention required to bring a fruit tree to bearing. <em>Ve-shomer 'adonav yekhubbad</em> — &ldquo;and whoever watches over his master will be honored.&rdquo; The parallel between agricultural stewardship and vocational faithfulness: the same quality of attentive care (<em>shamer</em>) that produces fruit from the tree produces honor from the master.</p>",
    "19": "<p><strong>ka-mayim ha-panim la-fanim</strong> — &ldquo;as in water face reflects face.&rdquo; The mirror-surface of still water (<em>mayim</em>) reflecting (<em>la-panim</em>) the face (<em>ha-panim</em>) that looks into it: a straightforward optical observation. Applied: <em>ken lev-ha'adam le'adam</em> — &ldquo;so the heart of a man reflects the man.&rdquo; The proverb probes the relationship between character and perception: we tend to perceive in others what we carry in ourselves, or alternatively, that people reflect each other through their interactions. The ambiguity is productive: the proverb works in both directions.</p>",
    "20": "<p><strong>she'ol va'avaddon lo' tisba'nah</strong> — &ldquo;Sheol and Abaddon are never satisfied.&rdquo; <em>She'ol</em> (H7585, the realm of the dead) and <em>'Avaddon</em> (H11, the place of destruction — from <em>'abad</em>, to perish; the angel of the abyss in Rev 9:11) are personified as mouths that are never full. <em>Ve'einei ha'adam lo' tishba'nah</em> — &ldquo;and the eyes of man are never satisfied.&rdquo; The parallel between the appetite of death and the appetite of human eyes (<em>'einayim</em>) is the darkest of the comparisons: human desire has the same insatiable structure as the underworld&rsquo;s appetite for the dead. Only Rev 22:4 (&ldquo;they will see his face&rdquo;) promises what will finally satisfy the eyes.</p>",
    "21": "<p><strong>matzreph lakkeseph ve-kur la-zahav</strong> — &ldquo;the crucible for silver and the furnace for gold.&rdquo; The metallurgical testing apparatus (<em>matzreph</em>, H4715, crucible) for silver and the <em>kur</em> (H3564, furnace/smelting oven) for gold are the instruments that test the metal&rsquo;s purity under heat. Applied: <em>ve'ish lemahalalhu</em> — &ldquo;and a man is tested by his praise.&rdquo; How a person responds to commendation reveals character as accurately as how a metal responds to heat. The response to praise — whether it inflates pride or is received with equanimity — is the social equivalent of the metallurgical test.</p>",
    "22": "<p><strong>im-tiktosh 'et-ha'evil ba-makhtesh</strong> — &ldquo;though you grind a fool in a mortar with a pestle.&rdquo; <em>Katash</em> (H3806, to pound/crush in a mortar) and <em>makhtesh</em> (H4388, mortar) describe the grinding process that reduces grain to flour. But the fool (<em>'evil</em>) ground with a pestle (<em>'eli</em>, H5940) among the grain will not have his foolishness (<em>'ivvalto</em>) separated out: <em>lo' tasur me'alav 'ivvalto</em> — &ldquo;his foolishness will not depart from him.&rdquo; The grinding metaphor, applied to the fool, reveals the intractability of a settled character: external pressure cannot change what has become dispositional.</p>",
    "23": "<p><strong>yado' teda' penei tzonecha</strong> — &ldquo;know well the state of your flocks.&rdquo; The pastoral section vv23-27 shifts from the interpersonal aphorisms to agricultural wisdom. <em>Yado' teda'</em> (H3045, the infinitive absolute emphasizing the thorough knowing) applied to <em>penei tzonecha</em> (the face/condition of your flock) means intimate, attentive knowledge of each animal&rsquo;s state. <em>Shith libbekha la'adarim</em> — &ldquo;and give careful attention to your herds.&rdquo; The doubled imperative (<em>yado' teda'</em> and <em>shith lev</em>) emphasizes that pastoral success requires engaged, not merely supervisory, attention.</p>",
    "24": "<p><strong>ki lo' le'olam chason</strong> — &ldquo;for riches do not last forever.&rdquo; <em>Chason</em> (H2633, treasure, wealth stored up) is not permanent; nor is the crown (<em>ve-'im nezer le-dor va-dor</em> — &ldquo;and does the crown last to all generations?&rdquo;). The impermanence of wealth and political power motivates the pastoral care of vv23-27: the flock is a renewable resource that requires attention, while stored wealth dissipates. The agricultural argument for active stewardship over passive wealth-preservation.</p>",
    "25": "<p><strong>galah chatzir ve-nir'ah deshe'</strong> — &ldquo;the hay is gone, the new growth appears.&rdquo; The agricultural cycle of cutting (<em>galah</em>, H1540, the hay is exposed/cut) and renewed growth (<em>deshe'</em>, H1877, fresh green growth, the first spring growth) describes the natural replenishment cycle. <em>Ve-ne'esfu 'ishvot harim</em> — &ldquo;and the herbage of the mountains is gathered.&rdquo; The seasonal abundance that follows from attention to the cycle is the point: stewardship aligned with natural cycles produces abundance.</p>",
    "26": "<p><strong>kevasim li-levushecha</strong> — &ldquo;the lambs will provide your clothing.&rdquo; The flock (<em>kevasim</em>, H3532, lambs) produces <em>levush</em> (clothing, H3830) — wool that is spun and woven. <em>Ve-ther sadeh mechir</em> — &ldquo;and the goats the price of a field.&rdquo; The goats&rsquo; productivity provides the capital for land acquisition. The pastoral-household economy of vv26-27 traces the chain from flock to clothing to field-purchase to sustenance: the self-sufficient agricultural household that attends to its animals is the concrete picture of the flourishing life that wisdom produces.</p>",
    "27": "<p><strong>ve-day chalevat izzim le-lachmecha</strong> — &ldquo;and there will be enough milk from the goats for your food.&rdquo; <em>Day</em> (H1767, sufficiency, enough — cf. Prov 25:16 <em>daieka</em>) is the wisdom standard for material well-being: not excess, but enough. The <em>chalevat izzim</em> (milk of goats) provides <em>lechem le-veithecha</em> (bread/food for your household) and sustenance for your servant girls (<em>na'arotecha</em>). The pastoral chain concludes with the household staff included in the provision: genuine agricultural stewardship sustains the entire community of dependents, not merely the owner. The concluding image of the well-run pastoral household is Proverbs&rsquo; picture of wisdom embodied in material life.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    total = sum(len(vv) for vv in PROVERBS.values())
    parts = ', '.join(f'ch{ch}={len(PROVERBS[ch])}' for ch in sorted(PROVERBS, key=int))
    print(f'Proverbs 25-27 mkt-original: {total} verses written ({parts}).')

if __name__ == '__main__':
    main()
